import React, { useEffect, useState, useCallback, useMemo } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  /* ───────── 1. GLOBAL BACKGROUND INJECTOR ───────── */
  // This forces the literal body of the browser to be black, killing all leaks.
  useEffect(() => {
    const originalBg = document.body.style.background;
    document.body.style.background = isDark ? '#000000' : '#ffffff';
    return () => { document.body.style.background = originalBg; };
  }, [isDark]);

  /* ───────── 2. API Logic ───────── */
  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_PURGE: Proceed?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("DATA_PURGED");
    } catch (err) { toast.error("PURGE_ERROR"); }
  };

  useEffect(() => { fetchHistory(); }, [fetchHistory]);

  /* ───────── 3. OLED Style Mapping ───────── */
  const theme = useMemo(() => ({
    bg: isDark ? '#000000' : '#ffffff',
    card: isDark ? '#000000' : '#ffffff',
    text: isDark ? '#ffffff' : '#000000',
    border: isDark ? '#1a1a1a' : '#e5e7eb',
    overlay: isDark ? 'rgba(0,0,0,0.98)' : 'rgba(255,255,255,0.9)',
    muted: isDark ? '#888' : '#666'
  }), [isDark]);

  if (loading) return <div style={{...centerStyle, color: 'var(--accent-primary)'}}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div className="reveal-node" style={{...viewportStyle, background: theme.bg}}>
      <div style={{...containerStyle, color: theme.text}}>
        
        {/* Header */}
        <div style={{...headerRow, borderBottom: `1px solid ${theme.border}`}}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
            <Archive size={28} color="var(--accent-primary)"/>
            <h2 style={{ fontSize: '1.4rem', fontWeight: 900, margin: 0, color: theme.text }}>STRATEGY_VAULT</h2>
          </div>
          <span style={vaultBadge}>{history.length} NODES</span>
        </div>

        {/* List */}
        <div style={listStyle}>
          {history.length === 0 ? (
            <div style={{...emptyStyle, border: `1px dashed ${theme.border}`, color: theme.muted}}>NO_DATA_SYNCED</div>
          ) : (
            history.map((item) => (
              <div key={item.id} className="vault-card" style={{...cardStyle, background: theme.card, border: `1px solid ${theme.border}`}}>
                <div style={{ flex: 1 }}>
                  <div style={tagRow}>
                    <span style={{ fontSize: '0.8rem', color: theme.muted, display: 'flex', alignItems: 'center', gap: '6px' }}>
                      <Calendar size={14}/> {new Date(item.created_at).toLocaleDateString()}
                    </span>
                    <span style={{ fontSize: '0.8rem', color: 'var(--accent-primary)', fontWeight: 800 }}>
                      <ShieldCheck size={14}/> RISK: {item.risk_score}
                    </span>
                  </div>
                  <h4 style={{ margin: 0, color: theme.text, fontSize: '1.1rem', fontWeight: 700 }}>{item.goal}</h4>
                </div>

                <div style={{...actionColumn, borderLeft: `1px solid ${theme.border}`}}>
                  <button onClick={() => setSelectedItem(item)} style={{...iconBtn, color: theme.muted}}><Eye size={22}/></button>
                  <button onClick={() => handleDelete(item.id)} style={{...iconBtn, color: '#ef4444'}}><Trash2 size={22}/></button>
                </div>
              </div>
            ))
          )}
        </div>

        {/* OLED Modal */}
        {selectedItem && (
          <div style={{...modalOverlay, background: theme.overlay}}>
            <div style={{...modalContent, background: theme.bg, border: `2px solid var(--accent-primary)`}}>
              <div style={{...modalHeader, background: theme.bg, borderBottom: `1px solid ${theme.border}`}}>
                <span style={{ color: 'var(--accent-primary)', fontWeight: 800 }}>NODE_DATA // ID_{selectedItem.id}</span>
                <button onClick={() => setSelectedItem(null)} style={{background: 'none', border: 'none', color: theme.text, cursor: 'pointer'}}><X size={28}/></button>
              </div>
              <div style={modalBody}>
                <h3 style={{ color: theme.text, fontSize: '1.6rem', fontWeight: 900, marginBottom: '2rem' }}>{selectedItem.goal}</h3>
                <div className={isDark ? "md-dark" : "md-light"}>
                  <p style={labelSmall}><AlignLeft size={16}/> SUMMARY</p>
                  <ReactMarkdown>{selectedItem.summary}</ReactMarkdown>
                  <hr style={{margin: '2rem 0', borderColor: theme.border}} />
                  <p style={labelSmall}><AlignLeft size={16}/> RATIONALE</p>
                  <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      <style>{`
        .md-dark p { color: #ffffff !important; line-height: 1.7; }
        .md-light p { color: #000000 !important; line-height: 1.7; }
        .vault-card:hover { border-color: var(--accent-primary) !important; }
        .reveal-node { animation: fadeIn 0.4s ease-out; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
    </div>
  );
};

/* ── UI Logic ── */
const viewportStyle = { width: '100%', minHeight: '100vh', display: 'flex', flexDirection: 'column' };
const containerStyle = { padding: '4rem 2rem', maxWidth: '1000px', margin: '0 auto', width: '100%' };
const headerRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '3rem', paddingBottom: '1.5rem' };
const vaultBadge = { fontSize: '0.75rem', color: 'var(--accent-primary)', fontWeight: 800, padding: '5px 12px', borderRadius: '6px', border: '1px solid' };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '1.5rem' };
const cardStyle = { display: 'flex', padding: '1.8rem', borderRadius: '15px', alignItems: 'center', transition: 'all 0.2s ease' };
const tagRow = { display: 'flex', gap: '20px', marginBottom: '10px' };
const actionColumn = { display: 'flex', gap: '20px', paddingLeft: '2rem', marginLeft: '1.5rem' };
const iconBtn = { background: 'none', border: 'none', cursor: 'pointer' };

const modalOverlay = { position: 'fixed', inset: 0, backdropFilter: 'blur(20px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999 };
const modalContent = { width: '92%', maxWidth: '850px', borderRadius: '25px', maxHeight: '85vh', display: 'flex', flexDirection: 'column', overflow: 'hidden' };
const modalHeader = { padding: '1.5rem 2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' };
const modalBody = { padding: '3rem', overflowY: 'auto' };
const labelSmall = { fontSize: '0.8rem', fontWeight: 900, color: 'var(--accent-primary)', marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '8px' };
const centerStyle = { height: '80vh', display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: 'monospace' };
const emptyStyle = { textAlign: 'center', padding: '10rem 0', borderRadius: '20px' };

export default VaultPage;
